query:
-- 检查是否还有乱码：body 中只含 base64 字符且不含空格的记录
SELECT COUNT(*) as possible_garbled 
FROM signals 
WHERE body REGEXP '^[A-Za-z0-9+/=]+$' AND LENGTH(body) > 10;

-- 查看最早的5条和最新的5条，确认内容正常
SELECT id, subject, LEFT(body, 80) as body_preview, receivedAt FROM signals ORDER BY receivedAt ASC LIMIT 5;
SELECT id, subject, LEFT(body, 80) as body_preview, receivedAt FROM signals ORDER BY receivedAt DESC LIMIT 5;

